SELECT AVG(average_putts_per_round) AS avg_putts_per_round
FROM putting
WHERE player_id = 1 AND year = 2010;

SELECT AVG(total_score) AS average_total_score
FROM player_tournament_participation
WHERE tournament_id = 1 AND player_id = 0;

SELECT total_putts
FROM putting
WHERE player_id = 0 AND year = 2023;

SELECT AVG(average_drive_distance) AS avg_drive_distance
FROM driving
WHERE player_id = 0 AND year = 2010;
